# Shapes module: Concrete shape implementations

from types import Entity, ShapeCategory, IMeasurable, IPositionable
from structures import Point, MathUtils

class Rectangle(Entity, IMeasurable, IPositionable):
    width: float
    height: float
    _pos: Point

    def __init__(self, id: int, width: float, height: float, x: float, y: float):
        super().__init__(id, ShapeCategory.TWO_D)
        self.width = width
        self.height = height
        self._pos = Point(x, y)

    @override
    def describe(self) -> str:
        return f"Rectangle {self.id}"

    @override
    def get_type_name(self) -> str:
        return "Rectangle"

    @override
    def get_area(self) -> float:
        return self.width * self.height

    @override
    def get_perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def get_position(self) -> tuple[float, float]:
        return (self._pos.x, self._pos.y)

class Circle(Entity, IMeasurable, IPositionable):
    radius: float
    _pos: Point

    def __init__(self, id: int, radius: float, x: float, y: float):
        super().__init__(id, ShapeCategory.TWO_D)
        self.radius = radius
        self._pos = Point(x, y)

    @override
    def describe(self) -> str:
        return f"Circle {self.id}"

    @override
    def get_type_name(self) -> str:
        return "Circle"

    @override
    def get_area(self) -> float:
        return MathUtils.circle_area(self.radius)

    @override
    def get_perimeter(self) -> float:
        return MathUtils.circle_perimeter(self.radius)

    @override
    def get_position(self) -> tuple[float, float]:
        return (self._pos.x, self._pos.y)

    def contains_point(self, p: Point) -> bool:
        return self._pos.distance_to(p) <= self.radius

class ShapeCollection:
    _shapes: list[Entity]

    def __init__(self):
        self._shapes = []

    def add(self, shape: Entity) -> None:
        self._shapes.append(shape)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self._shapes:
            if isinstance(shape, IMeasurable):
                total = total + cast(shape, IMeasurable).get_area()
        return total

    def count_by_category(self, cat: ShapeCategory) -> int:
        count: int = 0
        for shape in self._shapes:
            if shape.category == cat:
                count = count + 1
        return count
